import React, {useState} from 'react';


function msgBox(){

    return (
        <div className="msgBox">
            <span className="message-received">Mensagem recebida...</span>
            <span className="message-received">Mensagem recebida...</span>
            <span className="message-sent">Mensagem enviada...</span>
            <span className="message-received">Mensagem recebida...</span>
            <span className="message-received">😭</span>
        </div>
    );
}

export default msgBox;
